// batch_ingest.run_batch returns the grand totals dict.
const r = $input.first().json;
const seen = r.papers_seen ?? 0;
const processed = r.papers_processed ?? 0;
const eps = r.episodes_created ?? 0;
const ents = r.entities_added ?? r.entities_after - r.entities_before ?? 0;
const errs = r.errors ?? 0;
const noisy = (processed + eps + errs) > 0;
const summary = `🧠 extraction-tick  +${processed} papers  +${eps} episodes  ~${ents} entities  ${errs ? '⚠️ '+errs+' errors' : ''}`;
return [{ json: { summary, noisy, ...r } }];
